const ACHIEVEMENTS = [
  { name: 'Первый шаг к олимпу', description: 'Решите первую олимпиадную задачу', icon: '⛰️', xp: 50, rarity: 'COMMON', condition: { type: 'olympiad_solved', value: 1 } },
  { name: 'Олимпиадник', description: 'Решите 10 олимпиадных задач', icon: '🎖️', xp: 150, rarity: 'RARE', condition: { type: 'olympiad_solved', value: 10 } },
  { name: 'Звезда олимпиад', description: 'Решите 30 олимпиадных задач', icon: '🌟', xp: 400, rarity: 'EPIC', condition: { type: 'olympiad_solved', value: 30 } },
  { name: 'Сотня очков', description: 'Наберите 100 олимпиадных очков', icon: '💯', xp: 100, rarity: 'COMMON', condition: { type: 'olympiad_points', value: 100 } },
  { name: 'Пятьсот очков', description: 'Наберите 500 олимпиадных очков', icon: '🏆', xp: 300, rarity: 'EPIC', condition: { type: 'olympiad_points', value: 500 } },
  { name: 'Все ступени', description: 'Решите задачи всех четырёх уровней этапов', icon: '🪜', xp: 250, rarity: 'RARE', condition: { type: 'olympiad_levels', value: 4 } },
  { name: 'Эрудит', description: 'Решите олимпиадные задачи по трём разным предметам', icon: '🧠', xp: 200, rarity: 'RARE', condition: { type: 'olympiad_subjects', value: 3 } },
  { name: 'Республиканский уровень', description: 'Решите задачу республиканского этапа', icon: '🥇', xp: 200, rarity: 'EPIC', condition: { type: 'olympiad_republic', value: 1 } },
];

// ---------------------------------------------------------------------------

async function main() {
  const subjects = await prisma.subject.findMany({ select: { id: true, slug: true } });
  const bySlug = new Map(subjects.map(s => [s.slug, s.id]));

  let pCreated = 0, pUpdated = 0, pSkipped = 0;
  for (const p of PROBLEMS) {
    const subjectId = bySlug.get(p.slug);
    if (!subjectId) { console.warn(`! предмет не найден: ${p.slug} (задача ${p.title})`); pSkipped++; continue; }
    const externalId = `OLY-${p.slug}-${String(p.n).padStart(2, '0')}`;
    const data = {
      subjectId,
      title: p.title,
      content: p.content,
      answer: p.answer,
      answerType: 'TEXT',
      solution: p.solution,
      hints: JSON.stringify(p.hints),
      level: p.level,
      difficulty: p.difficulty,
      topic: p.topic,
      grade: '9–11',
      year: p.year,
      points: PTS[p.level],
      tags: JSON.stringify(p.tags),
      source: SOURCE,
      status: 'ACTIVE',
    };
    const existing = await prisma.olympiadProblem.findUnique({ where: { externalId } });
    if (existing) {
      await prisma.olympiadProblem.update({ where: { externalId }, data });
      pUpdated++;
    } else {
      await prisma.olympiadProblem.create({ data: { ...data, externalId } });
      pCreated++;
    }
  }

  let tCreated = 0, tUpdated = 0;
  for (const t of THEORY) {
    const subjectId = bySlug.get(t.slug);
    if (!subjectId) { console.warn(`! предмет не найден: ${t.slug} (теория ${t.title})`); continue; }
    const externalId = `OLYT-${t.slug}-${String(t.n).padStart(2, '0')}`;
    const data = {
      subjectId,
      title: t.title,
      content: t.content,
      level: t.level,
      topic: t.topic,
      order: t.n,
      tags: JSON.stringify(t.tags),
      status: 'ACTIVE',
    };
    const existing = await prisma.olympiadTheory.findUnique({ where: { externalId } });
    if (existing) { await prisma.olympiadTheory.update({ where: { externalId }, data }); tUpdated++; }
    else { await prisma.olympiadTheory.create({ data: { ...data, externalId } }); tCreated++; }
  }

  let aCreated = 0, aUpdated = 0;
  for (const a of ACHIEVEMENTS) {
    const data = {
      name: a.name,
      description: a.description,
      icon: a.icon,
      xp: a.xp,
      rarity: a.rarity,
      category: 'OLYMPIAD',
      condition: JSON.stringify(a.condition),
    };
    const existing = await prisma.achievement.findFirst({ where: { name: a.name, category: 'OLYMPIAD' } });
    if (existing) { await prisma.achievement.update({ where: { id: existing.id }, data }); aUpdated++; }
    else { await prisma.achievement.create({ data }); aCreated++; }
  }

  const [problems, theory, achievements] = await Promise.all([
    prisma.olympiadProblem.count(),
    prisma.olympiadTheory.count(),
    prisma.achievement.count({ where: { category: 'OLYMPIAD' } }),
  ]);
  console.log(`Задачи: +${pCreated} создано, ~${pUpdated} обновлено, ${pSkipped} пропущено. Всего в БД: ${problems}`);
  console.log(`Теория: +${tCreated} создано, ~${tUpdated} обновлено. Всего в БД: ${theory}`);
  console.log(`Достижения: +${aCreated} создано, ~${aUpdated} обновлено. Всего OLYMPIAD: ${achievements}`);
}

main()
  .catch((e) => { console.error(e); process.exitCode = 1; })
  .finally(() => prisma.$disconnect());
